label(scale(2.5)*project("B",Y,-X),(1/2,1/2,1));
label(scale(2.5)*project("R",Y,Z),(1,1/2,1/2));
label(scale(2.5)*project("R",X,Z),(1/2,0,1/2));

picture pic1;

drawCube(pic1,0,0,0);
label(pic1,scale(2.5)*project("B",Y,-X),(1/2,1/2,1));
