label(pic1,scale(2.5)*project("R",Y,Z),(0,1/2,1/2));
draw(pic1,(0,0,0)--(0,1,0)--(0,1,1),linetype("2 3"));
draw(pic1,(0,1,0)--(1,1,0),linetype("2 3"));

add(shift((1,1.5,0))*pic1);

picture pic2;

drawCube(pic2,0,0,0);
